CREATE TABLE journal_entries(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),reference_type text NOT NULL,reference_id uuid NOT NULL,currency char(3) NOT NULL,lines jsonb NOT NULL,posted_at timestamptz NOT NULL);
CREATE TABLE payment_refunds(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),payment_id uuid NOT NULL REFERENCES payments(id),amount_cents integer NOT NULL CHECK(amount_cents>0),reason text NOT NULL,provider_reference text NOT NULL,status text NOT NULL,created_at timestamptz NOT NULL);
CREATE TABLE bank_transactions(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),bank_account_id uuid NOT NULL,external_id text NOT NULL,amount_cents integer NOT NULL,currency char(3) NOT NULL,booked_at timestamptz NOT NULL,label text NOT NULL,matched_payment_id uuid REFERENCES payments(id),reconciled_at timestamptz,UNIQUE(tenant_id,bank_account_id,external_id),UNIQUE(tenant_id,matched_payment_id));
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['journal_entries','payment_refunds','bank_transactions'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
